svg.script:
// Core State
let cyclicX = 0;
let cyclicY = 0;
let isDragging = false;
let rotationAngle = 0;
const rpm = 3;
const bladeOffsets = [0, 90, 180, 270];

// Math Utils
const normalizeAngle = (a) => ((a % 360) + 360) % 360;

function calculatePhysics(x, y) {
  const magnitude = Math.min(Math.hypot(x, y), 1);
  const isActive = magnitude > 0.05;

  // Math.atan2 maps normal coords (y up, x right) to Math radians.
  // We flip Y here because in standard joystick, Y>0 is Forward.
  const rawPitchAngle = isActive ? Math.atan2(y, x) * (180 / Math.PI) : 0;
  const maxPitchAngle = normalizeAngle(rawPitchAngle);
  const maxLiftAngle = normalizeAngle(maxPitchAngle - 90);

  return { magnitude, maxPitchAngle, maxLiftAngle, isActive };
}

// Get Elements
const svgRoot = document.documentElement;
const stickHitbox = document.getElementById('stickHitbox');
const stickKnob = document.getElementById('stickKnob');
const resetBtnBg = document.getElementById('resetBtnBg');
const resetBtnText = document.getElementById('resetBtnText');

const pitchValueText = document.getElementById('pitchValueText');
const rollValueText = document.getElementById('rollValueText');
const eduIdle = document.getElementById('eduIdle');
const eduActive = document.getElementById('eduActive');

const heliSide = document.getElementById('heliSide');
const heliFront = document.getElementById('heliFront');
const pitchIndicator = document.getElementById('pitchIndicator');
const rollIndicator = document.getElementById('rollIndicator');

const vectorOverlay = document.getElementById('vectorOverlay');
const phaseArc = document.getElementById('phaseArc');
const phaseText = document.getElementById('phaseText');
const pitchVector = document.getElementById('pitchVector');
const liftVector = document.getElementById('liftVector');
const liftHeatmap = document.getElementById('liftHeatmap');

const bladeGroups = [
  document.getElementById('bladeGroup0'),
  document.getElementById('bladeGroup1'),
  document.getElementById('bladeGroup2'),
  document.getElementById('bladeGroup3')
];
const bladeRects = [
  document.getElementById('bladeRect0'),
  document.getElementById('bladeRect1'),
  document.getElementById('bladeRect2'),
  document.getElementById('bladeRect3')
];

// SVG Point Conversion
function getMouseCoords(e) {
  let clientX = e.clientX;
  let clientY = e.clientY;
  if (e.touches && e.touches.length > 0) {
    clientX = e.touches[0].clientX;
    clientY = e.touches[0].clientY;
  }
  const pt = svgRoot.createSVGPoint();
  pt.x = clientX;
  pt.y = clientY;
  // Get transform to the local coordinate system of the stick area
  const ctm = stickHitbox.getScreenCTM().inverse();
  return pt.matrixTransform(ctm);
}

// Interaction Handlers
function startDrag(e) {
  e.preventDefault();
  isDragging = true;
  updateStickPos(e);
}

function drag(e) {
  if (!isDragging) return;
  e.preventDefault();
  updateStickPos(e);
}

function stopDrag() {
  isDragging = false;
}

function resetStick() {
  cyclicX = 0;
  cyclicY = 0;
  updateUI();
}

function updateStickPos(e) {
  const pt = getMouseCoords(e);
  // Map [-140, 140] pixel range to [-1, 1] mathematical range
  let dx = pt.x / 140;
  let dy = pt.y / 140;

  const mag = Math.hypot(dx, dy);
  if (mag > 1) {
    dx /= mag;
    dy /= mag;
  }

  cyclicX = dx;
  cyclicY = -dy; // SVG +Y is down. Math +Y is up (Forward).
  updateUI();
}

// Attach Listeners
stickHitbox.addEventListener('mousedown', startDrag);
stickHitbox.addEventListener('touchstart', startDrag, {passive: false});
window.addEventListener('mousemove', drag);
window.addEventListener('touchmove', drag, {passive: false});
window.addEventListener('mouseup', stopDrag);
window.addEventListener('touchend', stopDrag);

resetBtnBg.addEventListener('click', resetStick);
resetBtnText.addEventListener('click', resetStick);

// Geometry Helpers
function getArcPath(x, y, radius, startAngle, endAngle) {
  // SVG angles are rotated by 90 degrees compared to standard math
  const svgStart = (startAngle - 90) * Math.PI / 180.0;
  const svgEnd = (endAngle - 90) * Math.PI / 180.0;

  const startX = x + radius * Math.cos(svgStart);
  const startY = y + radius * Math.sin(svgStart);
  const endX = x + radius * Math.cos(svgEnd);
  const endY = y + radius * Math.sin(svgEnd);

  return `M ${startX} ${startY} A ${radius} ${radius} 0 0 0 ${endX} ${endY}`;
}

function getPieSlice(x, y, radius, startAngle, endAngle) {
  const arc = getArcPath(x, y, radius, startAngle, endAngle);
  return `${arc} L ${x} ${y} Z`;
}

// Main UI Update loop for values
function updateUI() {
  // Move knob visually (map back to SVG -y coordinates)
  stickKnob.setAttribute('transform', `translate(${cyclicX * 140}, ${-cyclicY * 140})`);

  // Readouts
  const absY = Math.abs(cyclicY * 100).toFixed(0);
  const absX = Math.abs(cyclicX * 100).toFixed(0);

  pitchValueText.textContent = `${cyclicY > 0 ? 'FWD ' : cyclicY < 0 ? 'AFT ' : 'NEUTRAL '}${absY}%`;
  pitchValueText.setAttribute('fill', cyclicY > 0.1 ? '#d97706' : cyclicY < -0.1 ? '#0891b2' : '#334155');

  rollValueText.textContent = `${cyclicX > 0 ? 'RIGHT ' : cyclicX < 0 ? 'LEFT ' : 'NEUTRAL '}${absX}%`;
  rollValueText.setAttribute('fill', cyclicX > 0.1 ? '#d97706' : cyclicX < -0.1 ? '#0891b2' : '#334155');

  // Helicopter React Silhouettes
  heliSide.setAttribute('transform', `rotate(${cyclicY * 20}, 100, 70)`);
  heliFront.setAttribute('transform', `rotate(${cyclicX * 25}, 50, 70)`);

  // Indicators
  if (cyclicY > 0) {
    pitchIndicator.setAttribute('y', '80');
    pitchIndicator.setAttribute('height', '65');
  } else if (cyclicY < 0) {
    pitchIndicator.setAttribute('y', '145');
    pitchIndicator.setAttribute('height', '65');
  } else {
    pitchIndicator.setAttribute('y', '112.5');
    pitchIndicator.setAttribute('height', '65');
  }

  if (cyclicX > 0) {
    rollIndicator.setAttribute('x', '150');
    rollIndicator.setAttribute('width', '65');
  } else if (cyclicX < 0) {
    rollIndicator.setAttribute('x', '85');
    rollIndicator.setAttribute('width', '65');
  } else {
    rollIndicator.setAttribute('x', '117.5');
    rollIndicator.setAttribute('width', '65');
  }

  const physics = calculatePhysics(cyclicX, cyclicY);

  if (physics.isActive) {
    eduIdle.setAttribute('visibility', 'hidden');
    eduActive.setAttribute('visibility', 'visible');
    vectorOverlay.setAttribute('visibility', 'visible');

    // Draw vectors and arcs
    // Note: SVG math origin expects 0 to be Top (so we subtract 90 in angle math)
    phaseArc.setAttribute('d', getArcPath(0, 0, 100, physics.maxPitchAngle, physics.maxLiftAngle));

    // Position phase text halfway along arc
    const midAngle = physics.maxPitchAngle - 45; 
    const textX = 115 * Math.cos((midAngle - 90) * Math.PI / 180);
    const textY = 115 * Math.sin((midAngle - 90) * Math.PI / 180);
    phaseText.setAttribute('x', textX);
    phaseText.setAttribute('y', textY);
    phaseText.setAttribute('transform', `rotate(${midAngle}, ${textX}, ${textY})`);

    // Pitch Vector
    const px = 140 * Math.cos((physics.maxPitchAngle - 90) * Math.PI / 180);
    const py = 140 * Math.sin((physics.maxPitchAngle - 90) * Math.PI / 180);
    pitchVector.setAttribute('x2', px);
    pitchVector.setAttribute('y2', py);

    // Lift Vector
    const lx = 170 * Math.cos((physics.maxLiftAngle - 90) * Math.PI / 180);
    const ly = 170 * Math.sin((physics.maxLiftAngle - 90) * Math.PI / 180);
    liftVector.setAttribute('x2', lx);
    liftVector.setAttribute('y2', ly);

    // Lift Heatmap (draw a 180 degree cone around the lift axis)
    liftHeatmap.setAttribute('d', getPieSlice(0, 0, 195, physics.maxLiftAngle - 90, physics.maxLiftAngle + 90));
    liftHeatmap.setAttribute('fill-opacity', String(0.1 + physics.magnitude * 0.15));
  } else {
    eduIdle.setAttribute('visibility', 'visible');
    eduActive.setAttribute('visibility', 'hidden');
    vectorOverlay.setAttribute('visibility', 'hidden');
    liftHeatmap.setAttribute('d', '');
  }
}

// Continuous Animation Loop
function animate() {
  // Rotation decreases (CCW)
  rotationAngle = (rotationAngle - rpm + 360) % 360;

  for (let i = 0; i < 4; i++) {
    let bladeAzimuth = (rotationAngle + bladeOffsets[i]) % 360;
    let rad = bladeAzimuth * (Math.PI / 180);

    // Pitch mapping equation
    let pitchDelta = (-cyclicY * Math.sin(rad) + cyclicX * Math.cos(rad));

    // Simulate visual pitch depth
    let visualScaleY = 1 + Math.abs(pitchDelta) * 0.3; 

    bladeGroups[i].setAttribute('transform', `rotate(${bladeAzimuth - 90}) scale(1, ${visualScaleY})`);

    // Update shading based on pitch
    // HSL mapping: hsl(215, 20%, shade%)
    let shade = Math.max(20, Math.min(80, 50 + pitchDelta * 30));
    bladeRects[i].setAttribute('fill', `hsl(215, 20%, ${shade}%)`);
  }

  requestAnimationFrame(animate);
}

// Start Simulation
updateUI();
requestAnimationFrame(animate);
